// Convert Graph API message with expanded attachments to n8n format
const message = $input.first().json;
const attachments = message.attachments || [];
const binary = {};

for (let i = 0; i < attachments.length; i++) {
  const att = attachments[i];
  if (att.contentBytes) {
    binary['attachment_' + i] = {
      data: att.contentBytes,
      mimeType: att.contentType || 'application/octet-stream',
      fileName: att.name || 'attachment_' + i,
      fileSize: att.size || 0
    };
  }
}

const { attachments: _, ...messageJson } = message;

return [{ json: messageJson, binary }];

// Check binary attachments for XLSX/XLS files
const binary = $('Fetch Email').first().binary || {};
const binaryKeys = Object.keys(binary);
let hasXlsx = false;
let xlsxCount = 0;
const xlsxFiles = [];

// Order-related keywords in filenames (Croatian + English)
const ORDER_KEYWORDS = ['prednarudžba', 'prednarudzba', 'narudžba', 'narudzba', 'narudžbe',
  'narudžbenica', 'narudzbenica', 'transfer order', 'order', 'prednarudžbe', 'prednarudzbe',
  'to ', 'to-', 'to_'];

for (const key of binaryKeys) {
  const b = binary[key];
  const fileName = (b.fileName || '').toLowerCase();
  const mimeType = (b.mimeType || '').toLowerCase();
  if (fileName.endsWith('.xlsx') || fileName.endsWith('.xls') ||
      mimeType.includes('spreadsheetml') || mimeType.includes('ms-excel')) {
    hasXlsx = true;
    xlsxCount++;
    xlsxFiles.push({ key, fileName: b.fileName || key, fileNameLower: fileName });
  }
}

// If multiple XLSX, pick the one most likely to be an order by filename
let selectedXlsxKey = null;
if (xlsxCount > 1) {
  for (const f of xlsxFiles) {
    if (ORDER_KEYWORDS.some(kw => f.fileNameLower.includes(kw))) {
      selectedXlsxKey = f.key;
      break;
    }
  }
  // If no keyword match, use the first XLSX
  if (!selectedXlsxKey) selectedXlsxKey = xlsxFiles[0].key;
} else if (xlsxCount === 1) {
  selectedXlsxKey = xlsxFiles[0].key;
}

// Prepare plain-text input for AI classification
const emailBody = $('Fetch Email').first().json.body || {};
const bodyHtml = emailBody.content || '';
const bodyText = bodyHtml.replace(/<[^>]*>/g, '').substring(0, 2000);
const subject = $input.first().json.emailSubject || '';
const xlsxInfo = xlsxFiles.length > 0 ? '\n\nAttached XLSX: ' + xlsxFiles.map(f => f.fileName).join(', ') : '';
const aiClassifyInput = 'Subject: ' + subject + '\n\nBody:\n' + bodyText + xlsxInfo;

return [{ json: {
  ...$input.first().json,
  _hasXlsx: hasXlsx,
  _xlsxCount: xlsxCount,
  _xlsxNames: xlsxFiles.map(f => f.fileName),
  _selectedXlsxKey: selectedXlsxKey,
  _aiClassifyInput: aiClassifyInput
} }];

const data = $input.first().json;
const upstream = $('Classify Attachment').first().json;

let aiText = '';
try {
  aiText = (typeof data.text === 'string' && data.text)
    || (data.output && data.output.find(o => o.type === 'message')?.content?.[0]?.text)
    || (data.output && data.output[0]?.content?.[0]?.text)
    || '';
} catch (e) {
  // On AI failure, default to treating as valid order (fail open)
  return [{ json: { ...upstream, _isValidOrder: true, _classificationReason: 'AI parse error: ' + e.message } }];
}

let jsonStr = aiText.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  // JSON parse failure — fail open
  return [{ json: { ...upstream, _isValidOrder: true, _classificationReason: 'JSON parse error' } }];
}

return [{
  json: {
    ...upstream,
    _isValidOrder: parsed.isOrder !== false,  // fail open: only block if explicitly false
    _classificationReason: parsed.reason || ''
  }
}];

// Re-attach binary data from trigger and carry config
// Put the selected XLSX attachment into the 'data' key so WF-03 parser picks it up
const emailMeta = $('Extract Email Metadata').first().json;
const config = $('Config').first().json;
const classifyData = $('Classify Attachment').first().json;

const binary = $('Fetch Email').first().binary || {};
const binaryKeys = Object.keys(binary);
const renamedBinary = {};

// Use the pre-selected XLSX key from Classify Attachment (handles multi-XLSX filtering)
const xlsxKey = classifyData._selectedXlsxKey;

if (xlsxKey && binary[xlsxKey]) {
  renamedBinary.data = binary[xlsxKey];
  for (const key of binaryKeys) {
    if (key !== xlsxKey) renamedBinary[key] = binary[key];
  }
} else if (binaryKeys.length > 0) {
  // Fallback: use first attachment if no XLSX found
  renamedBinary.data = binary[binaryKeys[0]];
  for (let i = 1; i < binaryKeys.length; i++) {
    renamedBinary[binaryKeys[i]] = binary[binaryKeys[i]];
  }
}

return [{
  json: {
    config: config,
    senderEmail: emailMeta.senderEmail,
    emailSubject: emailMeta.emailSubject,
    emailId: emailMeta.emailId,
    receivedAt: emailMeta.receivedAt,
    businessCenter: config.businessCenterDefault,
    defaultDiscountPerc: config.defaultDiscountPerc
  },
  binary: renamedBinary
}];

// Package email body and metadata for WF-08
const emailMeta = $('Extract Email Metadata').first().json;
const config = $('Config').first().json;
const emailBody = $('Fetch Email').first().json.body || {};

return [{
  json: {
    emailBodyHtml: emailBody.content || '',
    emailBodyType: emailBody.contentType || 'html',
    senderEmail: emailMeta.senderEmail,
    emailSubject: emailMeta.emailSubject,
    config: config
  }
}];

// Build warning/error notification email for admin
// Includes full original email body and forwards attachments
const emailMeta = $('Extract Email Metadata').first().json;
const config = $('Config').first().json;
const emailBody = $('Fetch Email').first().json.body || {};
const originalHtml = emailBody.content || '';

// Detect which error branch
const inputData = $input.first().json;
const isAiNonOrder = inputData._isValidOrder === false;
const classifyData = $('Classify Attachment').first().json;
const isXlsxPath = classifyData._hasXlsx === true;
const isMultiXlsx = (classifyData._xlsxCount || 0) >= 2;

let title, description, errorType;
if (isMultiXlsx) {
  errorType = 'multiple_xlsx';
  title = 'Multiple XLSX Attachments';
  description = 'The email contains ' + classifyData._xlsxCount + ' spreadsheet attachments ('
    + (classifyData._xlsxNames || []).join(', ')
    + '). Only one spreadsheet per email is supported. '
    + 'Please ask the sender to send one spreadsheet per email, or process manually.';
} else if (isAiNonOrder) {
  errorType = 'not_an_order';
  title = 'Email Classified as Non-Order';
  description = 'The AI classifier determined this email is not a new pre-order. '
    + 'Reason: ' + (inputData._classificationReason || 'N/A') + '. '
    + 'Please review the original email below and process manually if needed.';
} else if (isXlsxPath) {
  errorType = 'xlsx_parse_failed';
  title = 'XLSX Parse Failed';
  description = 'An XLSX attachment was found but could not be parsed into order data. '
    + 'Either the file is corrupted, password-protected, or in an unexpected format, '
    + 'or the email does not contain an actual order.';
} else {
  errorType = 'no_order_data';
  title = 'No Order Data Found';
  description = 'No XLSX attachment was found and no order data could be extracted from the email body.';
}

const html = '<div style="font-family: Arial, sans-serif; max-width: 600px;">'
  + '<h2 style="color: #d35400;">' + title + '</h2>'
  + '<p>' + description + '</p>'
  + '<table style="border-collapse: collapse; width: 100%; margin: 16px 0;">'
  + '<tr><td style="padding: 8px; border: 1px solid #ddd; font-weight: bold;">From</td>'
  + '<td style="padding: 8px; border: 1px solid #ddd;">' + emailMeta.senderEmail + '</td></tr>'
  + '<tr><td style="padding: 8px; border: 1px solid #ddd; font-weight: bold;">Subject</td>'
  + '<td style="padding: 8px; border: 1px solid #ddd;">' + emailMeta.emailSubject + '</td></tr>'
  + '<tr><td style="padding: 8px; border: 1px solid #ddd; font-weight: bold;">Received</td>'
  + '<td style="padding: 8px; border: 1px solid #ddd;">' + emailMeta.receivedAt + '</td></tr>'
  + '<tr><td style="padding: 8px; border: 1px solid #ddd; font-weight: bold;">Error Type</td>'
  + '<td style="padding: 8px; border: 1px solid #ddd;">' + errorType + '</td></tr>'
  + '</table>'
  + '<h3>Original Email:</h3>'
  + '<div style="background: #f9f9f9; padding: 12px; border-left: 3px solid #d35400;">'
  + originalHtml
  + '</div>'
  + '<p style="color: #888; margin-top: 16px;">The email has been moved to the Error folder. Please review manually.</p>'
  + '</div>';

// Encode attachments into JSON (binary gets dropped by downstream Set/Execute nodes)
const binary = $('Fetch Email').first().binary || {};
const attachments = [];
for (const key of Object.keys(binary)) {
  const b = binary[key];
  if (b.data) {
    attachments.push({
      '@odata.type': '#microsoft.graph.fileAttachment',
      name: b.fileName || key,
      contentType: b.mimeType || 'application/octet-stream',
      contentBytes: b.data
    });
  }
}

// Build complete sendMail payload
const subject = '[Medika Pre-Orders] ' + title + ' - ' + emailMeta.emailSubject;
const message = {
  subject,
  body: { contentType: 'HTML', content: html },
  toRecipients: [{ emailAddress: { address: config.notifyEmail } }]
};
if (attachments.length > 0) {
  message.attachments = attachments;
}

return [{
  json: {
    sendMailPayload: { message },
    errorType: errorType,
    moveToError: true
  }
}];

// Consolidate all upstream data for WF-09: Process Order subflow
const parseResult = $input.first().json;
const emailMeta = $('Extract Email Metadata').first().json;
const config = $('Config').first().json;
const erpToken = $('WF-00b: Get ERP Token').first().json.accessToken;
const emailBody = $('Fetch Email').first().json.body || {};
const binary = $('Fetch Email').first().binary || {};

return [{
  json: {
    ...parseResult,
    emailId: emailMeta.emailId,
    senderEmail: emailMeta.senderEmail,
    emailSubject: emailMeta.emailSubject,
    receivedAt: emailMeta.receivedAt,
    config: config,
    accessToken: erpToken,
    emailBody: emailBody,
    emailBodyHtml: emailBody.content || ''
  },
  binary: binary
}];
